/**
 * Wire-nav step — back-fills `spokenInCountries` (via Country.primaryLanguage)
 * + `locales` (via Locale.language) and paired typed code sets.
 */
export function wireLanguageNav(): void {
  const spokenInByLang = new Map<LanguageCode, Country[]>();
  for (const country of CountryLookup.all) {
    const lang = country.primaryLanguage;
    if (lang === undefined) continue;
    let list = spokenInByLang.get(lang.iso6391Code);
    if (list === undefined) { list = []; spokenInByLang.set(lang.iso6391Code, list); }
    list.push(country);
  }
  for (const [code, list] of spokenInByLang) {
    const rec = LanguageLookup.byCode[code];
    if (rec === undefined) continue;
    const mut = rec as { -readonly [K in keyof Language]: Language[K] };
    mut.spokenInCountries = list;
    const codeSet = new Set<CountryCode>();
    for (const c of list) codeSet.add(c.iso31661Alpha2Code);
    mut.spokenInCountryIso31661Alpha2Codes = codeSet;
  }

  const localesByLang = new Map<LanguageCode, Locale[]>();
  for (const locale of LocaleLookup.all) {
    const lang = locale.language;
    if (lang === undefined) continue;
    let list = localesByLang.get(lang.iso6391Code);
    if (list === undefined) { list = []; localesByLang.set(lang.iso6391Code, list); }
    list.push(locale);
  }
  for (const [code, list] of localesByLang) {
    const rec = LanguageLookup.byCode[code];
    if (rec === undefined) continue;
    const mut = rec as { -readonly [K in keyof Language]: Language[K] };
    mut.locales = list;
    const codeSet = new Set<LocaleCode>();
    for (const l of list) codeSet.add(l.ietfBcp47Tag);
    mut.localeIetfBcp47Tags = codeSet;
  }
}